const item = $input.first().json;
const history = $items("Load Recent Messages")
  .map(entry => ({
    role: entry.json.role,
    content: entry.json.content,
  }))
  .filter(message => message.role && message.content);

const systemPrompt = item.system_prompt;
const messages = [
  { role: "system", content: systemPrompt },
  ...history,
];

return [{ json: { ...item, messages, system_prompt: systemPrompt } }];

const item = $input.first().json;
const messages = item.messages || [];
const prompt = messages.map(m => `${m.role}: ${m.content}`).join("

") + "

assistant:";
return [{ json: { ...item, prompt } }];

const item = $input.first().json;
const config = item.config || {};
const requestedTaskClass = item.force_task_class || item.request_type || "chat";
const policies = config.provider_policies || {};
const routeChain = policies[requestedTaskClass] || policies.chat || [];
const defaultCodexModel = config.codex?.model_alias || "gpt-5.4";
let selected = routeChain[0] || { provider: "ollama", model: "qwen3:14b" };

if (item.force_provider) {
  const matchedRoute = routeChain.find((route) => route.provider === item.force_provider);
  if (matchedRoute) {
    selected = matchedRoute;
  } else if (item.force_provider === "codex_oauth_worker") {
    selected = { provider: item.force_provider, model: defaultCodexModel };
  } else {
    selected = { provider: item.force_provider, model: item.force_model || selected.model };
  }
}

if (item.force_model) {
  selected = { provider: selected.provider, model: item.force_model };
}

return [{ json: { ...item, task_class: requestedTaskClass, provider: selected.provider, selected_model: selected.model, route_chain: routeChain, fallback_chain: routeChain.slice(1) } }];

const item = $input.first().json;
const messages = Array.isArray(item.messages) ? item.messages : [];
const lastUser = [...messages].reverse().find((message) => message.role === 'user');
const sourceText = (lastUser?.content || item.prompt || '').trim();
const findings = [];
let riskLevel = 'safe';

const destructiveRules = [
  { label: 'delete_or_rm', pattern: /(^|\s)(rm\s+-rf|rm\s+-r|rm\s+|delete\s+(the\s+)?file|delete\s+(the\s+)?directory|remove\s+(the\s+)?file|unlink\s+|shred\s+)/i, reason: 'Requests file deletion or removal.' },
  { label: 'docker_live_change', pattern: /docker\s+compose\s+(down|restart|up|stop)|docker\s+(restart|stop)\b/i, reason: 'Requests live container lifecycle changes.' },
  { label: 'destructive_sql', pattern: /\b(drop\s+table|drop\s+database|truncate\s+table|delete\s+from|alter\s+table\s+.*drop\s+column)\b/i, reason: 'Contains destructive SQL operations.' },
  { label: 'critical_move', pattern: /\b(move|mv|rename)\b.*\b(docker-compose\.ya?ml|\.env|systemd|workflow|workflows\/|base\/)\b/i, reason: 'Moves or renames critical runtime files.' },
];

const cautionRules = [
  { label: 'critical_file_edit', pattern: /\b(edit|modify|change|update|patch|rewrite)\b.*\b(docker-compose\.ya?ml|\.env(\.|\b)|systemd|service unit|workflow id|production workflow|ghost-chat-v3|Yh6h9OJyVCfREbp3)\b/i, reason: 'Touches critical runtime configuration or live workflow identifiers.' },
  { label: 'broad_sql', pattern: /\b(update|delete)\b.*\b(sql|postgres|database|table)\b/i, reason: 'Requests a database-changing operation.' },
  { label: 'infrastructure_change', pattern: /\b(deploy|deployment|infrastructure|nginx|kubernetes|compose file|dockerfile)\b/i, reason: 'Requests infrastructure-related changes.' },
];

for (const rule of destructiveRules) {
  if (rule.pattern.test(sourceText)) findings.push({ level: 'destructive', code: rule.label, reason: rule.reason });
}
if (!findings.length) {
  for (const rule of cautionRules) {
    if (rule.pattern.test(sourceText)) findings.push({ level: 'caution', code: rule.label, reason: rule.reason });
  }
}
if (findings.some((finding) => finding.level === 'destructive')) riskLevel = 'destructive';
else if (findings.some((finding) => finding.level === 'caution')) riskLevel = 'caution';

const approvalRequired = item.provider === 'codex_oauth_worker' && riskLevel !== 'safe';
const taskSummary = sourceText.replace(/\s+/g, ' ').trim().slice(0, 180);

return [{ json: {
  ...item,
  task_summary: taskSummary,
  approval_required: approvalRequired,
  risk_level: riskLevel,
  risk_reasons: findings.map((finding) => finding.reason),
  risk_codes: findings.map((finding) => finding.code),
  codex_command_status: approvalRequired ? 'blocked_pending_approval' : (item.provider === 'codex_oauth_worker' ? 'pending' : 'not_applicable'),
} }];

const response = $input.first().json;
const context = $('Expose Route Metadata').item.json;
const reply = response.response ?? response.message?.content ?? response.data?.response ?? '[no-reply]';
return [{ json: {
  ...context,
  ...response,
  reply,
  approval_required: context.approval_required || false,
  risk_level: context.risk_level || 'safe',
  risk_reasons: context.risk_reasons || [],
  risk_codes: context.risk_codes || [],
  task_summary: context.task_summary || '',
  command_success: true,
  command_exit_code: null,
  stdout_summary: '',
  stderr_summary: '',
  artifact_path: '',
  codex_command_status: 'not_applicable',
  error_type: '',
} }];

const item = $input.first().json;

const config = {
  openai: {
    endpoint: "https://api.openai.com/v1/responses",
    chat_model_alias: "gpt-4.1-mini",
    max_output_tokens: 500
  },
  codex: {
    model_alias: "gpt-5.4",
    worker_mode: "oauth_cli_wrapper"
  },
  ollama: {
    small_local_instruction_model: "qwen2.5:3b-instruct",
    chat_model: "qwen3:8b",
    strong_chat_model: "qwen3:14b",
    coding_model: "qwen2.5-coder:14b",
    strong_coding_model: "qwen3-coder:30b-a3b-q4_K_M"
  },
  provider_policies: {
    chat: [
      { provider: "openai_api", model: "gpt-4.1-mini" },
      { provider: "ollama", model: "qwen3:8b" },
      { provider: "ollama", model: "qwen3:14b" }
    ],
    technical_work: [
      { provider: "codex_oauth_worker", model: "gpt-5.4" },
      { provider: "ollama", model: "qwen2.5-coder:14b" },
      { provider: "ollama", model: "qwen3-coder:30b-a3b-q4_K_M" }
    ],
    lightweight_local_task: [
      { provider: "ollama", model: "qwen2.5:3b-instruct" },
      { provider: "ollama", model: "qwen3:8b" }
    ]
  }
};

return [{ json: { ...item, config } }];

const item = $input.first().json;
const safeConversationId = (item.conversation_id || 'reply').replace(/[^a-zA-Z0-9_-]/g, '_');
const model = item.selected_model || item.config?.codex?.model_alias || 'gpt-5.4';
const script = [
  'set +e',
  'mkdir -p /home/node/.n8n/ghost-artifacts',
  `convo="${safeConversationId}"`,
  'ts=$(date -u +%Y%m%dT%H%M%SZ)',
  `base="/home/node/.n8n/ghost-artifacts/${safeConversationId}-\${ts}"`,
  'reply_file="${base}.reply.txt"',
  'stdout_file="${base}.stdout.txt"',
  'stderr_file="${base}.stderr.txt"',
  'prompt="$1"',
  `/opt/ghost/bin/codex-safe exec --skip-git-repo-check --model ${model} --sandbox workspace-write -o "$reply_file" "$prompt" >"$stdout_file" 2>"$stderr_file"`,
  'status=$?',
  "node -e '
const fs = require("fs");
const [replyPath, stdoutPath, stderrPath, statusText] = process.argv.slice(1);
const read = (filePath) => { try { return fs.readFileSync(filePath, "utf8"); } catch { return ""; } };
const summarize = (value) => value.replace(/\s+/g, " " ).trim().slice(0, 600);
const reply = read(replyPath).trim();
const stdout = read(stdoutPath);
const stderr = read(stderrPath);
const exitCode = Number(statusText || 1);
const payload = {
  reply,
  artifact_path: replyPath,
  stdout_path: stdoutPath,
  stderr_path: stderrPath,
  success: exitCode === 0 && reply.length > 0,
  command_exit_code: exitCode,
  stdout_summary: summarize(stdout),
  stderr_summary: summarize(stderr),
};
process.stdout.write(JSON.stringify(payload));
' "$reply_file" "$stdout_file" "$stderr_file" "$status"",
].join('
');
return [{ json: { ...item, codex_command: 'sh -lc ' + JSON.stringify(script) + ' -- ' + JSON.stringify(item.prompt || '') } }];

const result = $input.first().json;
const context = $('Expose Route Metadata').item.json;
const rawStdout = typeof result.stdout === 'string' ? result.stdout.trim() : '';
let payload = {};
if (rawStdout) {
  try {
    payload = JSON.parse(rawStdout);
  } catch (error) {
    payload = {
      reply: rawStdout,
      success: true,
      command_exit_code: 0,
      stdout_summary: rawStdout.slice(0, 600),
      stderr_summary: typeof result.stderr === 'string' ? result.stderr.trim().slice(0, 600) : '',
      artifact_path: '',
    };
  }
}
const stderrSummary = payload.stderr_summary || (typeof result.stderr === 'string' ? result.stderr.trim().slice(0, 600) : '');
const commandSuccess = Boolean(payload.success);
const reply = (payload.reply || '').trim()
  || (commandSuccess
    ? '[no-codex-reply]'
    : `Codex execution failed${payload.command_exit_code !== undefined && payload.command_exit_code !== null ? ` (exit ${payload.command_exit_code})` : ''}. ${stderrSummary || 'No additional stderr was captured.'}`);
return [{ json: {
  ...context,
  ...result,
  codex_raw_result: payload,
  conversation_id: context.conversation_id || '',
  reply,
  provider_used: context.provider || '',
  model_used: context.selected_model || '',
  task_class: context.task_class || '',
  approval_required: context.approval_required || false,
  risk_level: context.risk_level || 'safe',
  risk_reasons: context.risk_reasons || [],
  risk_codes: context.risk_codes || [],
  task_summary: context.task_summary || '',
  command_success: commandSuccess,
  command_exit_code: payload.command_exit_code ?? null,
  stdout_summary: payload.stdout_summary || '',
  stderr_summary: stderrSummary,
  artifact_path: payload.artifact_path || '',
  codex_command_status: commandSuccess ? 'succeeded' : 'failed',
  error_type: commandSuccess ? '' : 'codex_command_failed',
} }];

const context = $input.first().json;
const reasons = Array.isArray(context.risk_reasons) && context.risk_reasons.length
  ? context.risk_reasons.join(' ')
  : 'Risk policy requires review.';
const reply = `Approval required before Codex execution. Risk level: ${context.risk_level || 'unknown'}. ${reasons}`;
return [{ json: {
  ...context,
  reply,
  provider_used: context.provider || '',
  model_used: context.selected_model || '',
  task_class: context.task_class || '',
  command_success: false,
  error_type: 'approval_required',
  codex_command_status: 'blocked_pending_approval',
  artifact_path: '',
  stdout_summary: '',
  stderr_summary: reasons,
  command_exit_code: null,
} }];
